var e=[{id:`L2_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_YOUNG`,text:{KOREA:`언니, 당주라는 건 무엇인가요?`,JPN:`姉さん、当主とは何ですか？`,ENG:`Sis, what does it mean to be Lady Nanahara?`,TWN:`姊姊，堂主是什麼？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`음, 가문연합을 대표해서 연합의 사람들을 책임지고 이끄는 사람이야.`,JPN:`うーん、連合の代表として連合の人たちを責任をもって率いる人のことよ。`,ENG:`Hmm. It means to be responsible for everyone in the Family Alliance.`,TWN:`嗯，就是代表家族聯盟，對聯盟的人負起責任，並且帶領大家的人。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_YOUNG`,text:{KOREA:`어르신들은 언니가 적임자니까 당주가 되는 거래요.`,JPN:`みんなは姉さんが適任者だから当主になるのだと言ってました。`,ENG:`The adults are saying that you are a perfect fit to be one.`,TWN:`長輩們都說姊姊是對的人，說姊姊要成為堂主。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_YOUNG`,text:{KOREA:`미안해요. 제가 적임자가 아니라서.`,JPN:`ごめんなさい。私が適任者ではなくて。`,ENG:`I'm sorry that I wasn't chosen.`,TWN:`對不起，我不是對的人。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_YOUNG`,text:{KOREA:`다른 사람들을 모두 책임지면, 언니가 무척 힘들 텐데……`,JPN:`他の人たち全員の責任を取ったら、姉さんがとても辛くなります……`,ENG:`It seems awfully hard to be responsible for everyone...`,TWN:`要對那麼多人負責，姊姊會很辛苦的……`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`조금 바빠지긴 하겠지만 괜찮아.`,JPN:`ちょっと忙しくなるだろうけど大丈夫よ。`,ENG:`I might be a little busy, but it's okay.`,TWN:`是會變得有點忙，但沒關係的。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`치후유가 곁에 있는데, 언니가 힘들 리가 없잖니?`,JPN:`千冬がそばにいるのに、私が辛いわけないでしょう？`,ENG:`You're by my side, Chifuyu. So how hard can it be?`,TWN:`有千冬在姊姊身邊，姊姊怎麼會辛苦呢？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_YOUNG`,text:{KOREA:`언니가 당주님이 되면…… 이제 예전처럼 지낼 수는 없는 거죠?`,JPN:`姉さんが当主になったら……もう昔のようには過ごせないのですよね？`,ENG:`If you become the head of Nanahara... does that mean we can't be friends anymore?`,TWN:`姊姊成為堂主後……我們就沒辦法像以前一樣相處吧？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`치후유. 이리 와봐.`,JPN:`千冬。こっちおいで。`,ENG:`Chifuyu, come here.`,TWN:`千冬，你過來。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`어때?`,JPN:`どう？`,ENG:`How does that feel?`,TWN:`感覺怎麼樣？`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_YOUNG`,text:{KOREA:`따뜻하고, 편안해요. 그야 치나츠 언니의 품이니까요.`,JPN:`温かくて、心地いいです。そりゃあ、千夏姉さんの腕の中ですから。`,ENG:`It's warm and comfy. Because it's a hug from you.`,TWN:`因為是千夏姊姊的擁抱，感覺好溫暖、好安心。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`후후……`,JPN:`ふふ……`,ENG:`Hah hah.`,TWN:`呵呵……`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`이렇게 다른 옷을 입고, 당주님이라고 불려도 언니는 변함없이 치후유의 언니야.`,JPN:`こうして違う服を着て、当主と呼ばれても私は変わらず千冬の姉さんよ。`,ENG:`Even if I wear different clothes, and people call me Lady Nanahara, it doesn't change the fact that I am still your sister.`,TWN:`就算我換上不同的衣服，大家稱我為堂主，但我還是千冬的姊姊，這一點是不會改變的。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`예전이랑 똑같아. 아무것도 바뀌지 않아.`,JPN:`昔と同じ。何も変わらない。`,ENG:`It's going to be just as it was. Nothing is going to change.`,TWN:`和以前一樣，不會有任何改變。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`그리고……`,JPN:`それに……`,ENG:`And...`,TWN:`還有……`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`사람에겐 각자 주어진 운명이 있는 거라고 해.`,JPN:`人にはそれぞれ与えられた運命があるんだって。`,ENG:`Each and every one of us is given a fate.`,TWN:`每個人的命運都不同，`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_YOUNG`,text:{KOREA:`나는 원래 당주가 될 운명이었으니, 치후유가 미안해할 필요는 없어.`,JPN:`私は元々当主になる運命だったから、千冬が悪く思う必要なんかないのよ。`,ENG:`I was destined to become the head of Nanahara. So you don't have to be sorry about that.`,TWN:`而我的命運就是要成為堂主，所以千冬你無需道歉。`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`평생 그토록 많은 무게를 견뎌내고도……`,JPN:`一生それほどたくさんのものに耐えて……`,ENG:`After enduring all that burden your entire life...`,TWN:`你這輩子已經承擔那麼多重任……`},stage:{bg:`NANAHARA_NORMAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};